function checkScope() {
  // 1. Declare a variable 'x' inside an 'if (true)' block using 'let'
  // 2. Try to access 'x' outside the block
  // Return [insideValue, outsideStatus]
}

solution:
function checkScope() {
  let insideValue;
  let outsideStatus;

  if (true) {
    let x = "block-scoped";
    insideValue = x;
  }

  try {
    outsideStatus = typeof x === 'undefined' ? 'ReferenceError' : x;
  } catch (e) {
    outsideStatus = 'ReferenceError';
  }

  return [insideValue, outsideStatus];
}

