}

solution:
function findTarget(matrix, target) {
  let position = null;

  outer: for (let i = 0; i < matrix.length; i++) {
    for (let j = 0; j < matrix[i].length; j++) {
      if (matrix[i][j] === target) {
        position = [i, j];
        break outer;
      }
    }
  }

  return position;
}

