starterCode:
function flattenMatrix(matrix) {
  const flat = [];
  // Use nested for loops
  return flat;
}

solution:
function flattenMatrix(matrix) {
  const flat = [];
  for (let i = 0; i < matrix.length; i++) {
    for (let j = 0; j < matrix[i].length; j++) {
      flat.push(matrix[i][j]);
    }
  }
  return flat;
}

